import{_ as r,o as t,c as a,ag as o}from"./chunks/framework.DXGyWiRo.js";const f=JSON.parse('{"title":"DUMLdore (DevinNorgarb fork) — firmware flashing tool","description":"Imported note from https://github.com/DevinNorgarb/DUMLdore","frontmatter":{"title":"DUMLdore (DevinNorgarb fork) — firmware flashing tool","description":"Imported note from https://github.com/DevinNorgarb/DUMLdore"},"headers":[],"relativePath":"pen-testing/drones/github-devinnorgarb-dumldore.md","filePath":"pen-testing/drones/github-devinnorgarb-dumldore.md"}'),i={name:"pen-testing/drones/github-devinnorgarb-dumldore.md"};function s(l,e,n,d,h,c){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="dumldore-devinnorgarb-fork-—-firmware-flashing-tool" tabindex="-1">DUMLdore (DevinNorgarb fork) — firmware flashing tool <a class="header-anchor" href="#dumldore-devinnorgarb-fork-—-firmware-flashing-tool" aria-label="Permalink to &quot;DUMLdore (DevinNorgarb fork) — firmware flashing tool&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://github.com/DevinNorgarb/DUMLdore" target="_blank" rel="noreferrer">https://github.com/DevinNorgarb/DUMLdore</a></li><li>Imported: 2026-04-21</li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p>This repository is described as <strong>DUMLdore firmware flashing tool v3.20</strong> (Windows-oriented workflow for DJI <code>dji_system.bin</code>-style updates).</p><h3 id="releases" tabindex="-1">Releases <a class="header-anchor" href="#releases" aria-label="Permalink to &quot;Releases&quot;">​</a></h3><ul><li>Releases are linked from the upstream project: <a href="https://github.com/jezzab/DUMLdore/releases" target="_blank" rel="noreferrer">jezzab/DUMLdore releases</a></li></ul><h3 id="usage-summary-from-readme" tabindex="-1">Usage summary (from README) <a class="header-anchor" href="#usage-summary-from-readme" aria-label="Permalink to &quot;Usage summary (from README)&quot;">​</a></h3><ul><li>Close <strong>DJI Assistant 2</strong> before use.</li><li>Connect USB from aircraft or RC to the PC, power on and wait for full boot.</li><li>Run <strong>DUMLdoreV3.exe</strong>.</li></ul><h3 id="ui-actions-described" tabindex="-1">UI actions described <a class="header-anchor" href="#ui-actions-described" aria-label="Permalink to &quot;UI actions described&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>LOAD</strong></td><td>Load a firmware file for flashing</td></tr><tr><td><strong>FLASH</strong></td><td>Upload firmware and start upgrade/downgrade</td></tr><tr><td><strong>PULL UPGRADE LOGS</strong></td><td>Download last upgrade log (tar/gzip)</td></tr><tr><td><strong>UNLOCK DEVICE</strong></td><td>Unlock devices grounded for missing a Sept 2017 firmware deadline</td></tr><tr><td><strong>ACTIVATE DEVICE</strong></td><td>Offline activation for <em>some</em> devices (Mavic Pro, P4, Spark); results may vary</td></tr><tr><td><strong>ADB ENABLE</strong></td><td>Enable ADB root shell quickly</td></tr><tr><td><strong>DOWNLOAD FIRMWARE</strong></td><td>Link to DankDroneDownloader</td></tr></tbody></table><h3 id="compatibility-as-listed" tabindex="-1">Compatibility (as listed) <a class="header-anchor" href="#compatibility-as-listed" aria-label="Permalink to &quot;Compatibility (as listed)&quot;">​</a></h3><ul><li><strong>Aircraft:</strong> P4, P4 Pro, Mavic, Spark, I2, Mavic Air</li><li><strong>Remote:</strong> Mavic</li><li><strong>Goggles:</strong> DJI (generic)</li></ul><h3 id="operational-note" tabindex="-1">Operational note <a class="header-anchor" href="#operational-note" aria-label="Permalink to &quot;Operational note&quot;">​</a></h3><ul><li>README recommends <strong>at least 50% battery</strong> before flashing.</li></ul><h3 id="related-deejayeyehackingclub-resources-readme-links" tabindex="-1">Related “DeejayeyeHackingClub” resources (README links) <a class="header-anchor" href="#related-deejayeyehackingclub-resources-readme-links" aria-label="Permalink to &quot;Related “DeejayeyeHackingClub” resources (README links)&quot;">​</a></h3><ul><li><a href="http://dji.retroroms.info/" target="_blank" rel="noreferrer">dji.retroroms.info</a> wiki-style reference</li><li><a href="https://github.com/fvantienen/dji_rev" target="_blank" rel="noreferrer">fvantienen/dji_rev</a> — firmware RE tooling</li><li><a href="https://github.com/Bin4ry/deejayeye-modder" target="_blank" rel="noreferrer">Bin4ry/deejayeye-modder</a> — APK tweaks</li><li><a href="https://github.com/hdnes/pyduml" target="_blank" rel="noreferrer">hdnes/pyduml</a> — Assistant-less pushes / DUML-related workflows</li><li><a href="https://github.com/MAVProxyUser/P0VsRedHerring" target="_blank" rel="noreferrer">MAVProxyUser/P0VsRedHerring</a> — historical exploit context (README description)</li><li><a href="https://github.com/MAVProxyUser/dji_system.bin" target="_blank" rel="noreferrer">MAVProxyUser/dji_system.bin</a> — firmware archive by MD5</li><li><a href="https://github.com/MAVProxyUser/firm_cache" target="_blank" rel="noreferrer">MAVProxyUser/firm_cache</a> — extracted firmware contents</li><li><a href="https://github.com/MAVProxyUser/DUMLrub" target="_blank" rel="noreferrer">MAVProxyUser/DUMLrub</a> — Ruby DUML / cherry-picking</li><li><a href="https://github.com/jezzab/DUMLdore" target="_blank" rel="noreferrer">jezzab/DUMLdore</a> — original DUMLdore repo</li><li><a href="https://github.com/MAVProxyUser/DJI_ftpd_aes_unscramble" target="_blank" rel="noreferrer">MAVProxyUser/DJI_ftpd_aes_unscramble</a> — FTP AES unscramble for some products</li><li><a href="https://github.com/darksimpson/jdjitools" target="_blank" rel="noreferrer">darksimpson/jdjitools</a> — Java DJI tools collection</li></ul><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Fork documents the same Windows flashing workflow as classic DUMLdore, with releases still pointed at <strong>jezzab</strong> upstream.</li><li>README is a practical checklist: Assistant off, USB, boot, then flash/load/logs/unlock paths.</li><li>Treat flashing and unlock/activation features as high-risk operations tied to specific legacy device support.</li></ul>',19)])])}const u=r(i,[["render",s]]);export{f as __pageData,u as default};
